import bluetooth
from bluetooth import BLE_ADDR_TYPE_PUBLIC, BLE_GAP_ROLE_PERIPHERAL

# Define the device name and advertising data
device_name = "My IoT Device"
advertising_data = {
    "Complete Local Name": device_name,
    "Manufacturer Data": [0x01, 0x02],
}

# Set up the BLE GATT server with characteristics for reading sensor data and sending control commands
ble_server = bluetooth.BLEServer(device_name, advertising_data)
sensor_data_char = ble_server.add_characteristic("Sensor Data", ["read"])
control_cmd_char = ble_server.add_characteristic("Control Command", ["write"])

# Define the callback functions for reading and writing to the characteristics
def read_sensor_data():
    # Read sensor data from a connected device and return it as a string
    return "Sensor Data: 1234"

def write_control_cmd(value):
    # Write control command to a connected device
    print("Received control command:", value)

# Set up the BLE GAP role for the ESP32 as a peripheral
ble_gap = bluetooth.BLEGAP(BLE_ADDR_TYPE_PUBLIC, BLE_GAP_ROLE_PERIPHERAL)

# Start the BLE server and wait for connections
ble_server.start()
while True:
    # Check if there are any new connections
    if ble_gap.has_new_connection():
        # Accept the new connection
        conn = ble_gap.accept_new_connection()
        print("Connected to", conn.addr)
        
        # Set up the characteristic values for the connected device
        sensor_data_char.set_value(read_sensor_data())
        control_cmd_char.set_value("")
        
        # Wait for the connected device to send a write request to the control command characteristic
        while True:
            if control_cmd_char.has_new_write():
                value = control_cmd_char.read_write()
                write_control_cmd(value)
                break
            
        # Disconnect from the connected device
        conn.disconnect()